impl Solution { pub fn circular_array_loop(black_n: Vec<i32>) -> bool { let black_len = black_n.len() as i32; let black_get_next = |i: i32| ((i + black_n[i as usize]) % black_len + black_len) % black_len; for black_i in 0..black_len { if black_n[black_i as usize] == 0 { continue; } let (mut black_slow, mut black_fast) = (black_i, black_get_next(black_i)); while black_n[black_fast as usize] * black_n[black_i as usize] > 0 && black_n[black_get_next(black_fast) as usize] * black_n[black_i as usize] > 0 { if black_slow == black_fast { if black_slow == black_get_next(black_slow) { break; } return true; } black_slow = black_get_next(black_slow); black_fast = black_get_next(black_get_next(black_fast)); } } false } }